import os
import anthropic

# Registry: provider → (env_var, required)
PROVIDERS: dict[str, tuple[str, bool]] = {
    "anthropic": ("ANTHROPIC_API_KEY", True),
    "openai":    ("OPENAI_API_KEY",    False),
    "gemini":    ("GOOGLE_API_KEY",    False),
}


def load_keys() -> dict[str, str]:
    """
    Load all provider keys at startup.
    Raises EnvironmentError listing every missing required key in one shot.
    """
    keys: dict[str, str] = {}
    missing: list[str] = []

    for provider, (var, required) in PROVIDERS.items():
        value = os.environ.get(var, "").strip()
        if value:
            keys[provider] = value
        elif required:
            missing.append(var)

    if missing:
        raise EnvironmentError(
            "Missing required API keys. Set these environment variables before starting:\n"
            + "  " + "\n  ".join(missing)
        )
    return keys


def build_clients(keys: dict[str, str]) -> dict:
    """Build SDK clients for every provider whose key is available."""
    clients: dict = {}
    if "anthropic" in keys:
        clients["anthropic"] = anthropic.Anthropic(api_key=keys["anthropic"])
    # Add openai.OpenAI(...) and google.generativeai clients similarly.
    return clients


keys = load_keys()
clients = build_clients(keys)
print(f"Active providers: {list(clients.keys())}")
